    if (!date) return null;

    const parts = date.split(/[\/\-]/);

    if (parts.length === 3) {
        const dd = parts[0].padStart(2,"0");
        const mm = parts[1].padStart(2,"0");
        const yyyy = parts[2];
        return Number(`${yyyy}${mm}${dd}`);
